import React from 'react'
import './Techstack.css';
import Zoom from 'react-reveal/Zoom';
import { TechstackList } from '../../utils/TechstackList';

const Techstack = () => {
 let data = [];
 data.push(TechstackList);
    return (
    <>
      <div className='container techstack' id="tech-stack">
          <h2 className='col-12 mt-3 text-center text-uppercase'>Technologies Stack</h2>
          <hr/>
          <p
          className='pb-2 text-center'>👉 including programming languages,framworks,databases,
            front-end and back-end tools and API's
          </p>
       <Zoom>   
        <div className="row">
          {TechstackList.map((tech)=>(
             <div key={tech._id} className="col-md-3">
                 <div className='card m-2'>
                    <div className='card-content'>
                        <div className="card-body">
                           <div className='media d-flex justify-content-center'>
                              <div className="alig-self-center">
                                {/* <tech.icon className='tech-icon'/>     */}
                              </div>
                              <div className="media-body">
                                <h5>{tech.name}</h5>
                              </div>
                           </div> 
                        </div>  
                    </div>

                 </div>
             </div>

          ))}
        </div>
       </Zoom> 
      </div>
      
    </>
  );
};

export default Techstack;