import React from 'react'
import { VerticalTimeline, VerticalTimelineElement }  from 'react-vertical-timeline-component';
import 'react-vertical-timeline-component/style.min.css';

import './Work.css';
const Work = () => {
  return (
     <>
       <div className=" work" id="Work-experiance">
        <div className="container work-exp">
            <h2 className='col-12 mt-3 text-center text-uppercase'>
             Work-Experiance
            </h2>
          <hr/>
          <VerticalTimeline lineColor='#1e1e2c'>
             <VerticalTimelineElement
                className="vertical-timeline-element--work"
                contentStyle={{ background: 'white', color: '#1e1e2c'}}
                contentArrowStyle={{ borderRight: '7px solid  gray' }}
                date="2025 - present"
                iconStyle={{ background: '#138781', color: '#fff' }}
                // icon={<WorkIcon /}
            >
                <h3 className="vertical-timeline-element-title">Software-Engineer</h3>
                <h4 className="vertical-timeline-element-subtitle">CS,IT</h4>
                <p>
                Website-designe, User Experience, Project Management, Team Leading
                </p>
            </VerticalTimelineElement>
             <VerticalTimelineElement
                className="vertical-timeline-element--work"
                contentStyle={{ background: 'white', color: 'black'}}
                contentArrowStyle={{ borderRight: '7px solid  gray' }}
                date="2025 - present"
                iconStyle={{ background: '#138781', color: '#fff' }}
                // icon={<WorkIcon /}
            >
                <h3 className="vertical-timeline-element-title">Mern-Stack Developer</h3>
                <h4 className="vertical-timeline-element-subtitle">xyz pvt ltd</h4>
                <p>
                Website-designe, User Experience, Project Management, Team Leading
                </p>
            </VerticalTimelineElement>
          </VerticalTimeline>
        </div>
       </div>
     </>
  )
}

export default Work