import React from 'react'
import { VerticalTimeline, VerticalTimelineElement }  from 'react-vertical-timeline-component';
import 'react-vertical-timeline-component/style.min.css';
import './Educations.css';

const Educations = () => {
  return (
  <>
     <div className="education" id="education">
          <h2 className='col-12 mt-3 text-center text-uppercase'>
            Education Details
          </h2>
          <hr/>
          <VerticalTimeline>
               <VerticalTimelineElement
                        className="vertical-timeline-element--work"
                        contentStyle={{ background: 'white', color: 'black' }}
                        contentArrowStyle={{ borderRight: '7px solid  gray' }}
                        date="2019-2020"
                        iconStyle={{ background: '#138781', color: 'white' }}
                        // icon={faCoffee}
                    >
                        <h3 className="vertical-timeline-element-title">Basic Computer</h3>
                        <h4 className="vertical-timeline-element-subtitle">Certified by NIIT-Delhi </h4>
                        
                </VerticalTimelineElement> 
                <VerticalTimelineElement
                        className="vertical-timeline-element--work"
                        contentStyle={{ background: 'white', color: 'black' }}
                        contentArrowStyle={{ borderRight: '7px solid  gray' }}
                        date="2021-2025"
                        iconStyle={{ background: '#138781', color: 'white' }}
                        // icon={faCoffee}
                    >
                        <h3 className="vertical-timeline-element-title">B.Tech</h3>
                        <h4 className="vertical-timeline-element-subtitle">RGPV,Bhopal</h4>
                        
                </VerticalTimelineElement>           
            </VerticalTimeline>
        </div>
      
  </>
)
}

export default Educations