import React from 'react'
import './Menus.css';
import Zoom from 'react-reveal/Zoom';
// import './IMG-20250507-WA0083.jpg';
import {Link } from 'react-scroll';
import Image from '../../assets/images/IMG-20250507-WA0083.jpg';
import {
   FcAbout, 
   FcBiotech, 
   FcBusinessContact, 
   FcBusinesswoman, 
   FcHome, 
   FcReadingEbook, 
   FcVideoProjector, 
  } from "react-icons/fc";
const Menus = ({toggle}) => {
  return (
  <>
  {toggle ? (
    <> 
    <Zoom>
    <div className='navbar-profile-pic'>
    <img 
    src={Image}
    alt='profile-img'/>
    </div>
    </Zoom>
      <div className='nav-items'>
    <div className='nav-item'>
        <div className='nav-link'>
        <Link 
        to="home" 
        spy={true} 
        smooth={true} 
        offset={-100} 
        duration={100} 
        >
        <FcHome/>
        Home
        </Link>        
        </div>
        <div className='nav-link'>
        <Link
          to="about" 
        spy={true} 
        smooth={true} 
        offset={-100} 
        duration={100}
          >
          <FcAbout/>
          About
        </Link>
        </div>
        <div className='nav-link'>
          <Link
          to="education" 
          spy={true} 
          smooth={true} 
          offset={-100} 
          duration={100}
          >
           <FcReadingEbook/>
           Education     
          </Link>
        </div>
        <div className='nav-link'>
          <Link
          to="tech-stack" 
          spy={true} 
          smooth={true} 
          offset={-100} 
          duration={100}
          >
           <FcBiotech/>
           Tech-Stack
          </Link>
        </div>
        <div className='nav-link'>
          <Link
            to="Projects" 
            spy={true} 
            smooth={true} 
            offset={-100} 
            duration={100}
          >
           <FcVideoProjector/>
            Projects 
          </Link>
         </div>
        <div className='nav-link'>
          <Link
            to="Work-experiance" 
            spy={true} 
            smooth={true} 
            offset={-100} 
            duration={100}
          >
           <FcBusinesswoman/>
           Work-Experiance  
          </Link>
        </div>
       <div className='nav-link'>
        <Link
            to="contact" 
            spy={true} 
            smooth={true} 
            offset={-100} 
            duration={100}
        >
        <FcBusinessContact/>
         Contact
        </Link>
      </div>      
   </div> 
  </div>
</>
):(
    <>
    <div className='nav-items'>
    <div className='nav-item'>
        <div className='nav-link'>
        <Link 
        to="home" 
        spy={true} 
        smooth={true} 
        offset={-100} 
        duration={100} 
        >
        <FcHome/>
        </Link>
        </div>
        <div className='nav-link'>
        <Link
          to="about" 
        spy={true} 
        smooth={true} 
        offset={-100} 
        duration={100}
          >
          <FcAbout/>
        </Link>
        </div>
        <div className='nav-link'>
         <Link
          to="education" 
          spy={true} 
          smooth={true} 
          offset={-100} 
          duration={100}
          >
           <FcReadingEbook/>
          </Link>
        </div>
        <div className='nav-link'>
        <Link
          to="tech-stack" 
          spy={true} 
          smooth={true} 
          offset={-100} 
          duration={100}
          >
           <FcBiotech/>
          </Link>
        </div>
        <div className='nav-link'>
         <Link
            to="Projects" 
            spy={true} 
            smooth={true} 
            offset={-100} 
            duration={100}
          >
           <FcVideoProjector/>
          </Link>
         </div>
        <div className='nav-link'>
        <Link
            to="Work-experiance" 
            spy={true} 
            smooth={true} 
            offset={-100} 
            duration={100}
          >
           <FcBusinesswoman/>
          </Link>
        </div>
       <div className='nav-link'>
        <Link
            to="contact" 
            spy={true} 
            smooth={true} 

            offset={-100} 
            duration={100}
        >
        <FcBusinessContact/>
        </Link>
      </div>      
   </div> 
  </div>
    </>
)}
    </>
);
};

export default Menus;

